# Tier 2c: Sweep reward_coeff — 160 configs
# Tier 3: Combined extreme configs — 244 configs
#
# Usage:
#   bash scripts/sweep_hyperparams.sh
#   bash scripts/sweep_hyperparams.sh cuda:7

set -euo pipefail

