CONFIGS["dto_lr0.01_scale1_iter200_flu_reward_only"]="--optimization_mode dto --lr 0.01 --init_logit_scale 1.0 --max_iters 200 --response_nll_coeff 0 --skill_fluency_coeff 0.5 --reward_coeff 2.0"
