CONFIGS["dto_lr0.05_scale2_iter200_no_nll"]="--optimization_mode dto --lr 0.05 --init_logit_scale 2.0 --max_iters 200 --response_nll_coeff 0 --skill_fluency_coeff 0.05 --reward_coeff 1.0"
